-- data_20260515200000_2026-05-15-duplicate-doi-dedup.sql
-- Data migration generated for DR-2026-05-15 §8.2c (genuine duplicate-DOI groups).
--
-- This file is forward-only and immutable once committed. If a correction is
-- needed, emit a NEW data migration that compensates — do not edit this file.
--
-- ============================================================================
-- BACKGROUND
-- ============================================================================
--
-- DR-2026-05-15 §8.2c surfaced four DOIs each present in evidence_sources as
-- multiple ref_ids. CrossRef resolution (this session) confirmed each DOI maps
-- to a single published work, so the multiple ref_ids are genuine duplicate-
-- ingestion events rather than intentional multi-section citations (which are
-- documented separately in test_db_integrity.py KNOWN_DUP_DOIS).
--
-- Per group, canonical ref_id selection methodology:
--   1. CrossRef resolution of the DOI yields authoritative title + authors.
--   2. The ref_id whose metadata most-closely matches CrossRef is canonical.
--   3. Tiebreaker: most FK references downstream (least churn cost to repoint).
--
-- ============================================================================
-- MERGE PLAN
-- ============================================================================
--
-- Group 1 — DOI 10.3390/ijerph18063203
--   Paper: Tola, Talu, Congiu, Bain, Lindert. "Built Environment Design and
--          People with Autism Spectrum Disorder (ASD): A Scoping Review."
--          Int. J. Environ. Res. Public Health, 2021.
--   Canonical: REF-00710 (full title match; correct 5-author list; tier 2;
--              has FK references in evidence_population_match + citation_mining
--              from session_2026-05-10e-slug3-adversarial)
--   Merge from: REF-00046 (slug ndv-aut-built-environment-quantified-thresholds,
--                          local NAT-01; partial title; tier 1 misclassification)
--               REF-00490 (slug cognitive-wayfinding-design,
--                          local CWD-07; partial title)
--               REF-00546 (slug sensory-relief-space-design,
--                          local SRS-06; WRONG primary author "Petaccia, G.")
--
-- Group 2 — DOI 10.1371/journal.pone.0291228
--   Paper: Lindsay, Fuentes, Ragunathan, Li, Ross. "Accessible independent
--          housing for people with disabilities: A scoping review of promising
--          practices." PLOS ONE, 2024.
--   Canonical: REF-00006 (correct "Lindsay, S." author initial; full title)
--   Merge from: REF-00154 (slug residential-accessible-home-case-studies,
--                          local RAH-08; WRONG "Lindsay, L." initial)
--
-- Group 3 — DOI 10.3233/978-1-61499-684-2-612
--   Paper: Nersveen, J. "Experimental Studies of Wheelchair and Walker Users
--          Passing Through Doors with Different Opening Designs." Studies in
--          Health Technology and Informatics, 2016. (NOTE: both ref_ids have
--          WRONG author attribution; this dedup eliminates one duplicate
--          but does not correct the Nersveen attribution — that is a separate
--          metadata fix to be authored in a future migration.)
--   Canonical: REF-00204 (better title; lower ref_id)
--   Merge from: REF-00455 (slug threshold-door-hardware,
--                          local TDH-15; abbreviated title; WRONG "Brandt, A.")
--
-- Group 4 — DOI 10.1080/10400430903520280
--   Paper: Steinfeld, Maisel, Feathers, D'Souza. "Anthropometry and Standards
--          for Wheeled Mobility: An International Comparison." Assistive
--          Technology, 2010.
--   Canonical: REF-00060 (correct Steinfeld attribution; title close match
--              to CrossRef "Anthropometry of Wheeled Mobility")
--   Merge from: REF-00023 (slug upper-limb-impairment-built-environment,
--                          local ULB-01; partial title; D'Souza listed as primary
--                          when CrossRef has Steinfeld as first author)
--
-- ============================================================================
-- FK PRE-CHECK (verified pre-authoring):
--   - source_slug_links:        6 rows to REPOINT (no slug collisions — each
--                                duplicate ref was created for a different slug,
--                                which is precisely why these duplicates exist)
--   - evidence_source_authors:  18 rows to DELETE (5+5+5+1+1+1)
--                                Canonicals retain their own author rows.
--   - evidence_population_match: 0 rows reference any non-canonical
--   - citation_mining:           0 rows reference any non-canonical
--   - reasoning_doc_citations:   0 rows (table is empty)
--   - evidence_sources.superseded_by_ref_id: 0 rows point at any non-canonical
--   - evidence_sources_v1_legacy: NOT TOUCHED (historical snapshot preserved)
--
-- Net effect:
--   evidence_sources:     675 → 669 (-6)
--   source_slug_links:    721 → 721 (unchanged — rows repointed, not deleted)
--   evidence_source_authors: 1069 → 1051 (-18)
--
-- ============================================================================

BEGIN;

-- -------- Group 1: ASD scoping review (Tola 2021) — canonical REF-00710 --------

UPDATE source_slug_links SET ref_id = 'REF-00710' WHERE ref_id = 'REF-00046';
UPDATE source_slug_links SET ref_id = 'REF-00710' WHERE ref_id = 'REF-00490';
UPDATE source_slug_links SET ref_id = 'REF-00710' WHERE ref_id = 'REF-00546';

DELETE FROM evidence_source_authors WHERE ref_id IN ('REF-00046','REF-00490','REF-00546');

DELETE FROM evidence_sources WHERE ref_id IN ('REF-00046','REF-00490','REF-00546');

-- -------- Group 2: Accessible housing (Lindsay 2024) — canonical REF-00006 --------

UPDATE source_slug_links SET ref_id = 'REF-00006' WHERE ref_id = 'REF-00154';

DELETE FROM evidence_source_authors WHERE ref_id = 'REF-00154';

DELETE FROM evidence_sources WHERE ref_id = 'REF-00154';

-- -------- Group 3: Wheelchair/walker (Nersveen 2016) — canonical REF-00204 --------

UPDATE source_slug_links SET ref_id = 'REF-00204' WHERE ref_id = 'REF-00455';

DELETE FROM evidence_source_authors WHERE ref_id = 'REF-00455';

DELETE FROM evidence_sources WHERE ref_id = 'REF-00455';

-- -------- Group 4: Wheeled mobility (Steinfeld 2010) — canonical REF-00060 --------

UPDATE source_slug_links SET ref_id = 'REF-00060' WHERE ref_id = 'REF-00023';

DELETE FROM evidence_source_authors WHERE ref_id = 'REF-00023';

DELETE FROM evidence_sources WHERE ref_id = 'REF-00023';

COMMIT;
